#include<bits/stdc++.h>
using namespace std;
long long mod=1234567891,n,k;
struct matrix
{
    long long a[32][32];
    matrix()
    {
        memset(a,0,sizeof(a));
    }
    friend matrix operator*(const matrix&a,const matrix&b)
    {
        matrix c;
        for(long long i=0;i<=(::k+1);i++)
        {
            for(long long j=0;j<=(::k+1);j++)
            {
                for(long long k=0;k<=(::k+1);k++)
                {
                    c.a[i][j]+=1ll*(a.a[i][k]%mod)*(b.a[k][j]%mod)%mod;
                    c.a[i][j]%=mod;
                }
            }
        }
        return c;
    }
}base,ans,tmp;
void fastpow(long long y)
{
    for(long long i=0;i<=k+1;i++)
    {
        ans.a[i][i]=1;
    }
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*base;
        }
        base=base*base;
        y/=2;
    }
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        scanf("%lld%lld",&n,&k);
        base=ans=tmp=matrix();
        for(long long i=1;i<=k;i++)
        {
            base.a[i][i-1]=k-i+1;
            base.a[i][i]=i;
        }
        base.a[k+1][k]=1;
        base.a[k+1][k+1]=1;
        tmp.a[0][0]=1;
        fastpow(n);
        ans=ans*tmp;
        printf("%lld\n",(ans.a[k][0]+ans.a[k+1][0])%mod);
    }
    return 0;
}
